import React, { useState } from 'react';
import type { Meta } from '@storybook/react';
import { Overflow } from '..';

export default {
  title: 'Components/Overflow/临时示例',
} satisfies Meta;

export const All = () => {
  const [width, setWidth] = useState(42);
  const [width2, setWidth2] = useState(0);
  const [count, setCount] = useState(2);
  return (
    <div>
      <div>
        <label>item count</label>
        <input value={count} type="number" onChange={e => setCount(Number(e.target.value))} />
      </div>
      <div>
        <label>container width</label>
        <input value={width} type="number" onChange={e => setWidth(Number(e.target.value))} />
      </div>
      <div>
        <label>{'suffix width: '}</label>
        <input value={width2} type="number: " onChange={e => setWidth2(Number(e.target.value))} />
      </div>
      <h4>Responsive</h4>
      <div>
        <Overflow
          style={{
            boxShadow: '0 0 0 1px grey',
            width,
          }}
          maxCount="responsive"
          keys={Array(count)
            .fill(0)
            .map((_, i) => i)}
          // suffixRenderer={() => <input style={{ width: width2 }} />}
        />
      </div>
      {/* <h4>{'Max Count'}</h4>
      <Overflow
        style={{
          width,
          border: '1px solid grey',
        }}
        maxCount={3}
        keys={Array(count)
          .fill(0)
          .map((_, i) => i)}
        suffixRenderer={() => <input style={{ width: width2 }} />}
      /> */}
    </div>
  );
};
